                    accept="image/*"
                    // Removed capture="environment" to allow gallery selection
                    ref={fileInputRef}
                    onChange={handleImageCapture}
                    className="hidden"
                  />
                  <button
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl p-4 flex flex-col items-center justify-center text-slate-500 dark:text-slate-400 hover:border-indigo-500 dark:hover:border-indigo-500 hover:text-indigo-500 dark:hover:text-indigo-500 transition-colors group"
                  >
                    <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mb-2 group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/20 transition-colors">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                      </svg>
                    </div>
                    <span className="text-xs font-bold">Upload Receipt</span>
                  </button>
                </div>
              ) : (
                <div className="relative group rounded-xl overflow-hidden border border-slate-200 dark:border-slate-700 w-full max-w-[150px] aspect-[3/4] bg-black">
                  <img 
                    src={receiptImage} 
                    alt="Receipt" 
                    className="w-full h-full object-cover opacity-90"
                  />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center space-x-2">
                    <a
                      href={receiptImage}
                      download={`receipt_${date}_${amount}.png`}
                      className="bg-white/20 backdrop-blur-md text-white p-2 rounded-full hover:bg-white/30 transition-colors shadow-lg"
                      title="Save to Device"
                      onClick={(e) => e.stopPropagation()}
                    >
                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    </a>
                    <button
                      type="button"
                      onClick={removeReceipt}
                      className="bg-red-500 text-white p-2 rounded-full hover:bg-red-600 transition-colors shadow-lg"
                      title="Remove Photo"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  </div>
                </div>
              )}
            </div>

            {!isEditMode && (
              <div className="bg-slate-50 dark:bg-slate-800/40 p-5 rounded-2xl border border-slate-100 dark:border-slate-800/60">
                <label className="flex items-center cursor-pointer select-none">
                  <input 
                    type="checkbox" 
                    className="w-5 h-5 rounded border-slate-300 dark:border-slate-600 text-indigo-600 focus:ring-indigo-500 transition-all" 
                    checked={isRecurring}
                    onChange={(e) => setIsRecurring(e.target.checked)}
                  />
                  <span className="ml-3 text-sm font-bold text-slate-700 dark:text-slate-300">Set as recurring payment</span>
                </label>

                {isRecurring && (
                  <div className="mt-5 animate-in fade-in slide-in-from-top-2 duration-300">
                    <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-3">Billing Cycle</label>
                    <div className="grid grid-cols-2 gap-2">
                      {Object.values(RecurringFrequency).map(freq => (
                        <button
                          key={freq}
                          type="button"
                          onClick={() => setFrequency(freq)}
                          className={`px-3 py-3 rounded-xl text-xs font-bold transition-all border ${frequency === freq 
                            ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100 dark:shadow-none' 
                            : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700 hover:border-indigo-300 dark:hover:border-indigo-800'}`}
                        >
                          {freq}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-5 md:py-4 rounded-2xl font-black text-base shadow-xl shadow-indigo-100 dark:shadow-none hover:bg-indigo-700 transition-all active:scale-[0.97] mb-safe"
          >
            {isEditMode ? 'Update Transaction' : 'Confirm Expense'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ExpenseForm;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { HashRouter as Router, Routes, Route, NavLink } from 'react-router-dom';
import { Expense, RecurringExpense, RecurringFrequency, CategoryItem, DefaultCategory } from './types';
import { DEFAULT_CATEGORIES } from './constants';
import { formatCurrency } from './utils';
import Dashboard from './components/Dashboard';
import ExpenseList from './components/ExpenseList';
import ExpenseForm from './components/ExpenseForm';
import RecurringManager from './components/RecurringManager';
import CategoryManager from './components/CategoryManager';
import Settings from './components/Settings';
import Onboarding from './components/Onboarding';

const AppLogo = ({ className = "w-6 h-6" }: { className?: string }) => (
  <svg className={className} fill="none" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
    <defs>
      <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="currentColor" stopOpacity="1" />
        <stop offset="100%" stopColor="currentColor" stopOpacity="0.5" />
      </linearGradient>
    </defs>
    {/* Wallet Icon */}
    <path stroke="url(#logoGradient)" strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
  </svg>
);

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('spendwise-expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [recurringExpenses, setRecurringExpenses] = useState<RecurringExpense[]>(() => {
    const saved = localStorage.getItem('spendwise-recurring');
    return saved ? JSON.parse(saved) : [];
  });

  const [customCategories, setCustomCategories] = useState<CategoryItem[]>(() => {
    const saved = localStorage.getItem('spendwise-custom-categories');
    return saved ? JSON.parse(saved) : [];
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('spendwise-theme');
    if (savedTheme) return savedTheme === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  const [showForm, setShowForm] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [showOnboarding, setShowOnboarding] = useState(() => {
    return !localStorage.getItem('spendwise-onboarded');
  });

  // Combine defaults with custom categories
  const allCategories = useMemo(() => {
    return [...DEFAULT_CATEGORIES, ...customCategories];
  }, [customCategories]);

  // Persistence
  useEffect(() => {
    localStorage.setItem('spendwise-expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('spendwise-recurring', JSON.stringify(recurringExpenses));
  }, [recurringExpenses]);

  useEffect(() => {
    localStorage.setItem('spendwise-custom-categories', JSON.stringify(customCategories));
  }, [customCategories]);

  // Theme management
  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) {
      root.classList.add('dark');
      localStorage.setItem('spendwise-theme', 'dark');
    } else {
      root.classList.remove('dark');
      localStorage.setItem('spendwise-theme', 'light');
    }
  }, [isDarkMode]);

  // Recurring processing logic
  const processRecurring = useCallback(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    let updatedRecurring = [...recurringExpenses];
    let newExpensesToAdd: Expense[] = [];
    let modified = false;

    updatedRecurring = updatedRecurring.map(rule => {
      if (!rule.isActive) return rule;

      let nextDate = new Date(rule.nextOccurrenceDate);
      nextDate.setHours(0, 0, 0, 0);

      const instancesToAdd: Expense[] = [];
      const currentRule = { ...rule };

      while (nextDate <= today) {
        modified = true;
        const newInstance: Expense = {
          id: Math.random().toString(36).substr(2, 9),
          amount: currentRule.amount,
          description: `${currentRule.description} (Recurring)`,
          category: currentRule.category,
          date: nextDate.toISOString().split('T')[0],
          bankName: currentRule.bankName,
          recurringId: currentRule.id
        };
        instancesToAdd.push(newInstance);

        if (currentRule.frequency === RecurringFrequency.DAILY) {
          nextDate.setDate(nextDate.getDate() + 1);
        } else if (currentRule.frequency === RecurringFrequency.WEEKLY) {
          nextDate.setDate(nextDate.getDate() + 7);
        } else if (currentRule.frequency === RecurringFrequency.MONTHLY) {
          nextDate.setMonth(nextDate.getMonth() + 1);
        } else if (currentRule.frequency === RecurringFrequency.YEARLY) {
          nextDate.setFullYear(nextDate.getFullYear() + 1);
        }
      }

      if (instancesToAdd.length > 0) {
        newExpensesToAdd = [...newExpensesToAdd, ...instancesToAdd];
        currentRule.nextOccurrenceDate = nextDate.toISOString().split('T')[0];
        return currentRule;
      }
      return rule;
    });

    if (modified) {
      setExpenses(prev => [...newExpensesToAdd, ...prev]);
      setRecurringExpenses(updatedRecurring);
    }
  }, [recurringExpenses]);

  useEffect(() => {
    processRecurring();
  }, [processRecurring]);

  const handleSaveExpense = (newExpenseData: Omit<Expense, 'id'>, recurringInfo?: { frequency: RecurringFrequency }) => {
    if (editingExpense) {
      setExpenses(prev => prev.map(e => 
        e.id === editingExpense.id ? { ...newExpenseData, id: e.id, recurringId: e.recurringId } : e
      ));
      setEditingExpense(null);
    } else {
      const id = Math.random().toString(36).substr(2, 9);
      const expense: Expense = { ...newExpenseData, id };
      setExpenses(prev => [expense, ...prev]);

      if (recurringInfo) {
        const nextDate = new Date(newExpenseData.date);
        if (recurringInfo.frequency === RecurringFrequency.DAILY) nextDate.setDate(nextDate.getDate() + 1);
        else if (recurringInfo.frequency === RecurringFrequency.WEEKLY) nextDate.setDate(nextDate.getDate() + 7);
        else if (recurringInfo.frequency === RecurringFrequency.MONTHLY) nextDate.setMonth(nextDate.getMonth() + 1);
        else if (recurringInfo.frequency === RecurringFrequency.YEARLY) nextDate.setFullYear(nextDate.getFullYear() + 1);

        const recurringRule: RecurringExpense = {
          id: Math.random().toString(36).substr(2, 9),
          amount: newExpenseData.amount,
          description: newExpenseData.description,
          category: newExpenseData.category,
          bankName: newExpenseData.bankName,
          frequency: recurringInfo.frequency,
          startDate: newExpenseData.date,
          nextOccurrenceDate: nextDate.toISOString().split('T')[0],
          isActive: true
        };
        setRecurringExpenses(prev => [...prev, recurringRule]);
      }
    }
    setShowForm(false);
  };

  const deleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleEditExpense = (expense: Expense) => {
    setEditingExpense(expense);
    setShowForm(true);
  };

  const deleteRecurring = (id: string) => {
    setRecurringExpenses(prev => prev.filter(r => r.id !== id));
  };

  const toggleRecurring = (id: string) => {
    setRecurringExpenses(prev => prev.map(r => 
      r.id === id ? { ...r, isActive: !r.isActive } : r
    ));
  };

  // Category Management Handlers
  const addCustomCategory = (name: string, color: string) => {
    // Prevent duplicates
    if (allCategories.some(c => c.name.toLowerCase() === name.toLowerCase())) {
      alert('Category already exists!');
      return;
    }
    const newCat: CategoryItem = {
      id: `custom_${Date.now()}`,
      name,
      color,
      isCustom: true
    };
    setCustomCategories(prev => [...prev, newCat]);
  };

  const deleteCustomCategory = (id: string) => {
    const categoryToDelete = customCategories.find(c => c.id === id);
    if (!categoryToDelete) return;

    // Check if being used
    const isUsed = expenses.some(e => e.category === categoryToDelete.name) || 
                   recurringExpenses.some(r => r.category === categoryToDelete.name);

    if (isUsed) {
      if (!confirm(`The category "${categoryToDelete.name}" is currently used in your transactions or recurring rules. Deleting it will keep the history but remove it from the list. Continue?`)) {
        return;
      }
    }
    setCustomCategories(prev => prev.filter(c => c.id !== id));
  };

  const handleCompleteOnboarding = () => {
    localStorage.setItem('spendwise-onboarded', 'true');
    setShowOnboarding(false);
  };

  const exportToCSV = () => {
    if (expenses.length === 0) {
      alert("No data to export!");
      return;
    }
    const headers = ["Date", "Description", "Category", "Amount", "Bank"];
    const rows = expenses.map(e => [
      e.date,
      `"${e.description.replace(/"/g, '""')}"`,
      e.category,
      e.amount,
      e.bankName || "N/A"
    ]);

    const csvContent = [headers, ...rows].map(r => r.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `spendwise_expenses_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
