};

export default App;

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';
import { Expense, CategoryItem } from '../types';
import { getCategoryIcon } from '../constants';
import { formatCurrency } from '../utils';

interface DashboardProps {
  expenses: Expense[];
  categories: CategoryItem[];
  monthlyBudget: number;
}

const Dashboard: React.FC<DashboardProps> = ({ expenses, categories, monthlyBudget }) => {
  const isDark = window.document.documentElement.classList.contains('dark');

  const getCategoryColor = (name: string) => {
    return categories.find(c => c.name === name)?.color || '#94a3b8';
  };

  const totalSpent = useMemo(() => 
    expenses.reduce((sum, e) => sum + e.amount, 0), 
  [expenses]);

  const categoryData = useMemo(() => {
    // Get all unique categories present in expenses
    const usedCategories = Array.from(new Set(expenses.map(e => e.category))) as string[];

    const data = usedCategories.map(catName => ({
      name: catName,
      value: expenses.filter(e => e.category === catName).reduce((sum, e) => sum + e.amount, 0),
      color: getCategoryColor(catName)
    })).filter(d => d.value > 0);
    return data;
  }, [expenses, categories]);

  const dailyData = useMemo(() => {
    const last30Days = [...Array(30)].map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      return d.toISOString().split('T')[0];
    }).reverse();

    return last30Days.map(date => ({
      date: new Date(date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }),
      amount: expenses
        .filter(e => e.date === date)
        .reduce((sum, e) => sum + e.amount, 0)
    }));
  }, [expenses]);

  // Calculate 30-day averages per category
  const categoryAverages30Days = useMemo(() => {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    thirtyDaysAgo.setHours(0, 0, 0, 0);

    const recentExpenses = expenses.filter(e => new Date(e.date) >= thirtyDaysAgo);
    const usedCategories = Array.from(new Set(recentExpenses.map(e => e.category))) as string[];

    return usedCategories.map(catName => {
      const totalInCategory = recentExpenses
        .filter(e => e.category === catName)
        .reduce((sum, e) => sum + e.amount, 0);

      return {
        category: catName,
        total: totalInCategory,
        average: totalInCategory / 30,
        color: getCategoryColor(catName)
      };
    }).filter(item => item.total > 0)
      .sort((a, b) => b.average - a.average);
  }, [expenses, categories]);

  const bankData = useMemo(() => {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    thirtyDaysAgo.setHours(0, 0, 0, 0);

    const recentExpenses = expenses.filter(e => new Date(e.date) >= thirtyDaysAgo);
    const bankMap = new Map<string, number>();

    recentExpenses.forEach(e => {
      if (e.bankName) {
        const current = bankMap.get(e.bankName) || 0;
        bankMap.set(e.bankName, current + e.amount);
      }
    });

    return Array.from(bankMap.entries())
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  }, [expenses]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
          <p className="text-slate-500 dark:text-slate-400 text-xs md:text-sm font-medium">Total Spending</p>
          <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">{formatCurrency(totalSpent)}</h3>
          <div className="mt-4 flex items-center text-emerald-600 dark:text-emerald-400 text-[10px] md:text-xs font-semibold">
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
            Overall history
          </div>
        </div>
        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
          <p className="text-slate-500 dark:text-slate-400 text-xs md:text-sm font-medium">Monthly Budget</p>
          <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">{formatCurrency(monthlyBudget)}</h3>
          <div className="mt-4 w-full bg-slate-100 dark:bg-slate-800 h-2 rounded-full overflow-hidden">
            <div 
              className={`h-full rounded-full transition-all duration-500 ${
                totalSpent > monthlyBudget ? 'bg-red-500' : 'bg-blue-500 dark:bg-blue-600'
              }`}
              style={{ width: `${Math.min((totalSpent / monthlyBudget) * 100, 100)}%` }}
            />
          </div>
        </div>
        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 sm:col-span-2 md:col-span-1">
          <p className="text-slate-500 dark:text-slate-400 text-xs md:text-sm font-medium">Highest Category</p>
          <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1 truncate">
            {categoryData.length > 0 
              ? [...categoryData].sort((a, b) => b.value - a.value)[0].name.split(' ')[0]
              : 'N/A'}
          </h3>
          <p className="text-slate-400 dark:text-slate-500 text-[10px] md:text-xs mt-4 italic">Updated just now</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h4 className="text-slate-800 dark:text-slate-200 font-semibold mb-6 text-sm md:text-base">Spending Trend (Last 30 Days)</h4>
          <div className="h-48 md:h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDark ? "#1e293b" : "#f1f5f9"} />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#94a3b8', fontSize: 10}} 
                  minTickGap={15}
                />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} width={40} />
                <Tooltip 
                  cursor={{fill: isDark ? '#1e293b' : '#f8fafc'}}
                  formatter={(value: number) => [formatCurrency(value), 'Amount']}
                  contentStyle={{ 
                    borderRadius: '12px', 
                    border: 'none', 
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)',
                    backgroundColor: isDark ? '#1e293b' : '#ffffff',
                    color: isDark ? '#f1f5f9' : '#1e293b',
                    fontSize: '12px'
                  }}
                />
                <Bar dataKey="amount" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h4 className="text-slate-800 dark:text-slate-200 font-semibold mb-6 text-sm md:text-base">Distribution</h4>
          <div className="h-48 md:h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={50}
                  outerRadius={70}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => [formatCurrency(value), 'Spent']}
                  contentStyle={{
                    borderRadius: '12px',
                    border: 'none',
                    backgroundColor: isDark ? '#1e293b' : '#ffffff',
                    color: isDark ? '#f1f5f9' : '#1e293b',
                    fontSize: '12px'
                  }}
                />
                <Legend 
                  iconType="circle" 
                  wrapperStyle={{fontSize: '10px', color: '#64748b', paddingTop: '10px'}} 
                  layout="horizontal"
                  verticalAlign="bottom"
                  align="center"
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Bank Breakdown Section */}
      {bankData.length > 0 && (
        <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
          <h4 className="text-slate-800 dark:text-slate-200 font-semibold mb-6 text-sm md:text-base">Bank Breakdown (Last 30 Days)</h4>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart layout="vertical" data={bankData} margin={{ top: 0, right: 30, left: 20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke={isDark ? "#1e293b" : "#f1f5f9"} />
                <XAxis type="number" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} tickFormatter={(value) => formatCurrency(value)} />
                <YAxis dataKey="name" type="category" width={100} axisLine={false} tickLine={false} tick={{fill: isDark ? '#e2e8f0' : '#475569', fontSize: 12, fontWeight: 500}} />
                <Tooltip 
                  cursor={{fill: isDark ? '#1e293b' : '#f8fafc'}}
                  formatter={(value: number) => [formatCurrency(value), 'Spent']}
                  contentStyle={{ 
                    borderRadius: '12px', 
                    border: 'none', 
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)',
                    backgroundColor: isDark ? '#1e293b' : '#ffffff',
                    color: isDark ? '#f1f5f9' : '#1e293b',
                    fontSize: '12px'
                  }}
                />
                <Bar dataKey="value" fill="#818cf8" radius={[0, 4, 4, 0]} barSize={24} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {/* 30-Day Averages Section */}
      <div className="bg-white dark:bg-slate-900 p-5 md:p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
        <div className="flex justify-between items-center mb-6">
          <h4 className="text-slate-800 dark:text-slate-200 font-semibold text-sm md:text-base">30-Day Category Averages</h4>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-50 dark:bg-slate-800 px-2 py-1 rounded">Daily Burn Rate</span>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
          {categoryAverages30Days.length > 0 ? (
            categoryAverages30Days.map((item) => (
              <div key={item.category} className="p-4 rounded-xl bg-slate-50 dark:bg-slate-800/50 border border-slate-100 dark:border-slate-700/50 flex items-center space-x-4">
                <div 
                  className="w-10 h-10 rounded-lg flex items-center justify-center text-white shrink-0"
                  style={{ backgroundColor: item.color }}
                >
                  {getCategoryIcon(item.category)}
                </div>
                <div className="min-w-0 flex-1">
                   <p className="text-xs font-bold text-slate-500 dark:text-slate-400 truncate">{item.category}</p>
                   <p className="text-sm font-black text-slate-900 dark:text-white">{formatCurrency(item.average)}/day</p>
                </div>
              </div>
            ))
          ) : (
            <div className="col-span-full py-8 text-center text-slate-400 dark:text-slate-500 text-sm">
              Not enough data for 30-day averages yet.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef } from 'react';
import { Expense, RecurringExpense, CategoryItem } from '../types';

interface SettingsProps {
  expenses: Expense[];
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  recurringExpenses: RecurringExpense[];
  setRecurringExpenses: React.Dispatch<React.SetStateAction<RecurringExpense[]>>;
  customCategories: CategoryItem[];
  setCustomCategories: React.Dispatch<React.SetStateAction<CategoryItem[]>>;
  monthlyBudget: number;
  setMonthlyBudget: React.Dispatch<React.SetStateAction<number>>;
}

const Settings: React.FC<SettingsProps> = ({
  expenses, setExpenses,
  recurringExpenses, setRecurringExpenses,
  customCategories, setCustomCategories,
  monthlyBudget, setMonthlyBudget
}) => {
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [budgetInput, setBudgetInput] = useState(monthlyBudget.toString());
  const jsonFileInputRef = useRef<HTMLInputElement>(null);
  const csvFileInputRef = useRef<HTMLInputElement>(null);

  const handleUpdateBudget = () => {
    const val = parseFloat(budgetInput);
    if (!isNaN(val) && val >= 0) {
      setMonthlyBudget(val);
      alert('Monthly budget updated successfully!');
    } else {
      alert('Please enter a valid amount.');
    }
  };

  const handleClearData = () => {
    localStorage.removeItem('spendwise-expenses');
    localStorage.removeItem('spendwise-recurring');
    localStorage.removeItem('spendwise-custom-categories');
    localStorage.removeItem('spendwise-onboarded');
    localStorage.removeItem('spendwise-theme');
    localStorage.removeItem('spendwise-budget');
    window.location.reload();
  };

  const exportJSON = () => {
    const data = {
      version: 1,
      timestamp: new Date().toISOString(),
      expenses,
      recurringExpenses,
      customCategories,
      monthlyBudget
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `spendwise_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportCSV = () => {
    if (expenses.length === 0) {
      alert("No data to export!");
      return;
    }
    const headers = ["Date", "Description", "Category", "Amount", "Bank"];
    const rows = expenses.map(e => [
      e.date,
      `"${e.description.replace(/"/g, '""')}"`,
      e.category,
      e.amount,
      e.bankName || ""
    ]);

    const csvContent = [headers, ...rows].map(r => r.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `spendwise_expenses_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleJSONImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        let importedCount = 0;

        if (data.expenses && Array.isArray(data.expenses)) {
          const existingIds = new Set(expenses.map(e => e.id));
          const newExpenses = data.expenses.filter((e: Expense) => !existingIds.has(e.id));
          if (newExpenses.length > 0) {
            setExpenses(prev => [...prev, ...newExpenses]);
            importedCount += newExpenses.length;
          }
        }

        if (data.customCategories && Array.isArray(data.customCategories)) {
          const existingIds = new Set(customCategories.map(c => c.id));
          const newCats = data.customCategories.filter((c: CategoryItem) => !existingIds.has(c.id));
          if (newCats.length > 0) {
            setCustomCategories(prev => [...prev, ...newCats]);
          }
        }

        if (data.recurringExpenses && Array.isArray(data.recurringExpenses)) {
          const existingIds = new Set(recurringExpenses.map(r => r.id));
          const newRec = data.recurringExpenses.filter((r: RecurringExpense) => !existingIds.has(r.id));
          if (newRec.length > 0) {
            setRecurringExpenses(prev => [...prev, ...newRec]);
          }
        }

        if (data.monthlyBudget && typeof data.monthlyBudget === 'number') {
            setMonthlyBudget(data.monthlyBudget);
            setBudgetInput(data.monthlyBudget.toString());
        }

        alert(`Backup imported successfully! Added ${importedCount} transactions.`);
        if (jsonFileInputRef.current) jsonFileInputRef.current.value = '';
      } catch (err) {
        alert('Invalid backup file. Please check the file format.');
      }
    };
    reader.readAsText(file);
  };

  const handleCSVImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split('\n');
      const newExpenses: Expense[] = [];
      let skipped = 0;

      // Expecting Header: Date, Description, Category, Amount, Bank
      for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        // Simple regex to split by comma but ignore commas inside quotes
        const parts = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

        if (parts.length >= 4) {
          const date = parts[0].trim();
          const description = parts[1].replace(/^"|"$/g, '').trim();
          const category = parts[2].trim();
          const amount = parseFloat(parts[3]);
          const bank = parts[4] ? parts[4].replace(/^"|"$/g, '').trim() : undefined;

          if (date && description && !isNaN(amount)) {
            newExpenses.push({
              id: Math.random().toString(36).substr(2, 9),
              date,
              description,
              category, 
              amount,
              bankName: bank
            });
          } else {
            skipped++;
          }
        } else {
          skipped++;
        }
      }

      if (newExpenses.length > 0) {
        setExpenses(prev => [...prev, ...newExpenses]);
        alert(`Successfully imported ${newExpenses.length} transactions from CSV.${skipped > 0 ? ` Skipped ${skipped} invalid lines.` : ''}`);
      } else {
        alert('No valid transactions found in CSV. Ensure format is: Date, Description, Category, Amount, Bank');
      }
      if (csvFileInputRef.current) csvFileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h2 className="text-2xl md:text-3xl font-black text-slate-900 dark:text-white tracking-tight">Settings</h2>

      {/* General Preferences: Budget */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100 dark:border-slate-800">
        <div className="flex items-start space-x-4 mb-6">
          <div className="w-12 h-12 bg-blue-50 dark:bg-blue-900/30 rounded-2xl flex items-center justify-center text-blue-600 dark:text-blue-400 shrink-0">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-900 dark:text-white">General Preferences</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
              Customize your experience.
            </p>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 items-end">
          <div className="flex-1 w-full">
            <label className="block text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">
              Monthly Budget Goal (₹)
            </label>
            <input
              type="number"
              className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-semibold"
              value={budgetInput}
              onChange={(e) => setBudgetInput(e.target.value)}
            />
          </div>
          <button
            onClick={handleUpdateBudget}
            className="w-full md:w-auto px-6 py-3.5 bg-indigo-600 text-white font-bold rounded-xl shadow-lg shadow-indigo-100 dark:shadow-none hover:bg-indigo-700 transition-all h-[50px]"
          >
            Update Budget
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100 dark:border-slate-800">
        <div className="flex items-start space-x-4 mb-6">
          <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/30 rounded-2xl flex items-center justify-center text-indigo-600 dark:text-indigo-400 shrink-0">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2M8 7H6a2 2 0 00-2 2v10a2 2 0 002 2h8a2 2 0 002-2v-2" /></svg>
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-900 dark:text-white">Data Import & Export</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
              Backup your data securely or transfer it to another device.
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-3">
             <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300 uppercase tracking-wider">Export</h4>
             <button
               onClick={exportCSV}
               className="w-full px-4 py-3 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 font-bold rounded-xl hover:border-indigo-500 dark:hover:border-indigo-500 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all flex items-center justify-center group"
             >
               <svg className="w-5 h-5 mr-2 text-slate-400 group-hover:text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
               Export to CSV (Spreadsheet)
             </button>
             <button
               onClick={exportJSON}
               className="w-full px-4 py-3 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 font-bold rounded-xl hover:border-indigo-500 dark:hover:border-indigo-500 hover:text-indigo-600 dark:hover:text-indigo-400 transition-all flex items-center justify-center group"
             >
               <svg className="w-5 h-5 mr-2 text-slate-400 group-hover:text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
               Full Backup (JSON)
             </button>
          </div>

          <div className="space-y-3">
             <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300 uppercase tracking-wider">Import</h4>
             <div className="relative">
               <input
                 type="file"
                 accept=".csv"
                 ref={csvFileInputRef}
                 onChange={handleCSVImport}
                 className="hidden"
               />
               <button
                 onClick={() => csvFileInputRef.current?.click()}
                 className="w-full px-4 py-3 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 font-bold rounded-xl hover:border-emerald-500 dark:hover:border-emerald-500 hover:text-emerald-600 dark:hover:text-emerald-400 transition-all flex items-center justify-center group"
               >
                 <svg className="w-5 h-5 mr-2 text-slate-400 group-hover:text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m-4-4v12" /></svg>
                 Import CSV
               </button>
             </div>
             <div className="relative">
               <input
                 type="file"
                 accept=".json"
                 ref={jsonFileInputRef}
                 onChange={handleJSONImport}
                 className="hidden"
               />
               <button
                 onClick={() => jsonFileInputRef.current?.click()}
                 className="w-full px-4 py-3 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-700 font-bold rounded-xl hover:border-emerald-500 dark:hover:border-emerald-500 hover:text-emerald-600 dark:hover:text-emerald-400 transition-all flex items-center justify-center group"
               >
                 <svg className="w-5 h-5 mr-2 text-slate-400 group-hover:text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
                 Restore Backup (JSON)
               </button>
             </div>
          </div>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100 dark:border-slate-800">
        <div className="flex items-start space-x-4 mb-6">
          <div className="w-12 h-12 bg-red-50 dark:bg-red-900/30 rounded-2xl flex items-center justify-center text-red-600 dark:text-red-400 shrink-0">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
          </div>
          <div>
            <h3 className="text-xl font-bold text-slate-900 dark:text-white">Danger Zone</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
              Manage your local data. All expenses are stored in your browser's local storage.
            </p>
          </div>
        </div>

        <div className="space-y-4">
          {!showClearConfirm ? (
            <button
              onClick={() => setShowClearConfirm(true)}
              className="w-full md:w-auto px-6 py-3 bg-white dark:bg-slate-800 text-red-500 border border-slate-200 dark:border-slate-700 font-bold rounded-xl hover:bg-red-50 dark:hover:bg-red-900/20 transition-all flex items-center justify-center"
            >
              <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              Clear All Data
            </button>
          ) : (
            <div className="bg-red-50 dark:bg-red-900/10 p-4 rounded-xl border border-red-100 dark:border-red-900/30">
              <p className="text-sm font-bold text-red-600 dark:text-red-400 mb-3">
                Are you sure? This will delete all your expenses and cannot be undone.
              </p>
              <div className="flex space-x-3">
                <button
                  onClick={handleClearData}
                  className="px-4 py-2 bg-red-600 text-white font-bold rounded-lg text-sm hover:bg-red-700 transition-colors"
                >
                  Yes, Delete Everything
                </button>
                <button
                  onClick={() => setShowClearConfirm(false)}
                  className="px-4 py-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold rounded-lg text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                >
                  Cancel
                </button>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="bg-indigo-50 dark:bg-indigo-900/20 rounded-3xl p-6 md:p-8 border border-indigo-100 dark:border-indigo-800/50">
        <h3 className="text-lg font-bold text-indigo-900 dark:text-white mb-2">About SpendWise</h3>
        <p className="text-indigo-700 dark:text-indigo-300 text-sm leading-relaxed mb-4">
          SpendWise helps you track daily expenses efficiently.
          Your financial data stays on your device.
        </p>
        <p className="text-xs text-indigo-500 dark:text-indigo-400 font-medium">
          Version 1.0.0
        </p>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { RecurringExpense, CategoryItem } from '../types';
import { getCategoryIcon } from '../constants';
import { formatCurrency } from '../utils';

interface RecurringManagerProps {
  recurringExpenses: RecurringExpense[];
  onDelete: (id: string) => void;
  onToggle: (id: string) => void;
  categories: CategoryItem[];
}

const RecurringManager: React.FC<RecurringManagerProps> = ({ recurringExpenses, onDelete, onToggle, categories }) => {
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const getCategoryColor = (name: string) => {
    return categories.find(c => c.name === name)?.color || '#94a3b8';
  };

  const ruleToDelete = recurringExpenses.find(r => r.id === deleteConfirmId);

  if (recurringExpenses.length === 0) {
    return (
      <div className="text-center py-20 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-200 dark:border-slate-800">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-full mb-4">
          <svg className="w-8 h-8 text-slate-300 dark:text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
        </div>
        <p className="text-slate-500 dark:text-slate-400 font-medium">No recurring expenses set up.</p>
        <p className="text-slate-400 dark:text-slate-500 text-sm mt-1">Add automated payments via the Add Expense form.</p>
      </div>
    );
  }

  return (
    <>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {recurringExpenses.map((rule) => {
          const nextDueDate = new Date(rule.nextOccurrenceDate);
          nextDueDate.setHours(0, 0, 0, 0);
          const isPastDue = rule.isActive && nextDueDate < today;
          const isDueToday = rule.isActive && nextDueDate.getTime() === today.getTime();
          const categoryColor = getCategoryColor(rule.category);

          return (
            <div 
              key={rule.id} 
              className={`bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border transition-all duration-300 group relative ${
                rule.isActive 
                  ? isPastDue 
                    ? 'border-red-300 dark:border-red-900/50 bg-red-50/30 dark:bg-red-900/10' 
                    : isDueToday
                      ? 'border-amber-300 dark:border-amber-900/50 bg-amber-50/30 dark:bg-amber-900/10'
                      : 'border-slate-100 dark:border-slate-800' 
                  : 'border-slate-200 dark:border-slate-800 opacity-60 grayscale-[0.5]'
              }`}
            >
              {/* Pulsing Indicator */}
              {isPastDue && (
                <div className="absolute -top-1 -right-1 flex h-5 w-5 z-10">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-5 w-5 bg-red-500 shadow-sm border-2 border-white dark:border-slate-900"></span>
                </div>
              )}
              {!isPastDue && isDueToday && (
                <div className="absolute -top-1 -right-1 flex h-5 w-5 z-10">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-5 w-5 bg-amber-500 shadow-sm border-2 border-white dark:border-slate-900"></span>
                </div>
              )}

              <div className="flex justify-between items-start mb-6">
                <div 
                  className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-sm"
                  style={{ 
                    backgroundColor: rule.isActive 
                      ? (isPastDue ? '#ef4444' : isDueToday ? '#f59e0b' : categoryColor) 
                      : '#94a3b8' 
                  }}
                >
                  {getCategoryIcon(rule.category)}
                </div>
                <div className="flex flex-col items-end space-y-2">
                  <div className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                    rule.isActive 
                      ? isPastDue 
                        ? 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-400' 
                        : isDueToday
                          ? 'bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-400'
                          : 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' 
                      : 'bg-slate-100 dark:bg-slate-800 text-slate-500'
                  }`}>
                    {rule.frequency}
                  </div>
                  <button 
                    onClick={() => onToggle(rule.id)}
                    className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded transition-colors ${
                      rule.isActive 
                        ? isPastDue ? 'text-red-600 hover:text-red-700' : isDueToday ? 'text-amber-600 hover:text-amber-700' : 'text-emerald-600 hover:text-emerald-700' 
                        : 'text-slate-400 hover:text-indigo-500'
                    }`}
                  >
                    {rule.isActive ? (isPastDue ? 'Overdue' : isDueToday ? 'Due Today' : 'Active') : 'Paused'}
                  </button>
                </div>
              </div>

              <h4 className="font-bold text-slate-800 dark:text-slate-200 text-lg mb-1 truncate">{rule.description}</h4>
              {rule.bankName && (
                <p className="text-xs font-bold text-indigo-500 dark:text-indigo-400 mb-2 truncate">{rule.bankName}</p>
              )}
              <p className="text-2xl font-black text-slate-900 dark:text-white mb-4">{formatCurrency(rule.amount)}</p>

              <div className="space-y-2 border-t border-slate-50 dark:border-slate-800 pt-4">
                <div className="flex justify-between text-xs">
                  <span className="text-slate-400 dark:text-slate-500">Next Due:</span>
                  <div className="text-right">
                    <span className={`font-semibold ${
                      isPastDue ? 'text-red-600 dark:text-red-400' : isDueToday ? 'text-amber-600 dark:text-amber-400' : rule.isActive ? 'text-slate-700 dark:text-slate-300' : 'text-slate-400'
                    }`}>
                      {rule.isActive 
                        ? nextDueDate.toLocaleDateString('en-IN', { month: 'short', day: 'numeric', year: 'numeric' })
                        : 'Paused'}
                    </span>
                    {isPastDue && <div className="text-[10px] font-bold text-red-500 uppercase mt-0.5">Missed Payment</div>}
                    {!isPastDue && isDueToday && <div className="text-[10px] font-bold text-amber-500 uppercase mt-0.5">Payment due now</div>}
                  </div>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <div className="flex items-center overflow-hidden mr-2">
                    <span className="text-slate-400 dark:text-slate-500 shrink-0">Category:</span>
                    <span className="font-semibold text-slate-700 dark:text-slate-300 truncate ml-2">{rule.category}</span>
                  </div>
                  <button 
                    onClick={(e) => {
                      e.stopPropagation();
                      setDeleteConfirmId(rule.id);
