import React, { useState } from 'react';
import { RecurringExpense, CategoryItem } from '../types';
import { getCategoryIcon } from '../constants';
import { formatCurrency } from '../utils';

interface RecurringManagerProps {
  recurringExpenses: RecurringExpense[];
  onDelete: (id: string) => void;
  onEdit: (expense: RecurringExpense) => void;
  onToggle: (id: string) => void;
  categories: CategoryItem[];
}

const RecurringManager: React.FC<RecurringManagerProps> = ({ recurringExpenses, onDelete, onEdit, onToggle, categories }) => {
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const getCategoryColor = (name: string) => {
    return categories.find(c => c.name === name)?.color || '#94a3b8';
  };

  const ruleToDelete = recurringExpenses.find(r => r.id === deleteConfirmId);

  if (recurringExpenses.length === 0) {
    return (
      <div className="text-center py-20 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-200 dark:border-slate-800">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-full mb-4">
          <svg className="w-8 h-8 text-slate-300 dark:text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
        </div>
        <p className="text-slate-500 dark:text-slate-400 font-medium">No recurring expenses set up.</p>
        <p className="text-slate-400 dark:text-slate-500 text-sm mt-1">Add automated payments via the Add Expense form.</p>
      </div>
    );
  }

  return (
    <>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {recurringExpenses.map((rule) => {
          const nextDueDate = new Date(rule.nextOccurrenceDate);
          nextDueDate.setHours(0, 0, 0, 0);
          const isPastDue = rule.isActive && nextDueDate < today;
          const isDueToday = rule.isActive && nextDueDate.getTime() === today.getTime();
          const categoryColor = getCategoryColor(rule.category);

          return (
            <div 
              key={rule.id} 
              className={`bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border transition-all duration-300 group relative ${
                rule.isActive 
                  ? isPastDue 
                    ? 'border-red-300 dark:border-red-900/50 bg-red-50/30 dark:bg-red-900/10' 
                    : isDueToday
                      ? 'border-amber-300 dark:border-amber-900/50 bg-amber-50/30 dark:bg-amber-900/10'
                      : 'border-slate-100 dark:border-slate-800' 
                  : 'border-slate-200 dark:border-slate-800 opacity-60 grayscale-[0.5]'
              }`}
            >
              {/* Pulsing Indicator */}
              {isPastDue && (
                <div className="absolute -top-1 -right-1 flex h-5 w-5 z-10">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-5 w-5 bg-red-500 shadow-sm border-2 border-white dark:border-slate-900"></span>
                </div>
              )}
              {!isPastDue && isDueToday && (
                <div className="absolute -top-1 -right-1 flex h-5 w-5 z-10">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-5 w-5 bg-amber-500 shadow-sm border-2 border-white dark:border-slate-900"></span>
                </div>
              )}

              <div className="flex justify-between items-start mb-6">
                <div 
                  className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-sm"
                  style={{ 
                    backgroundColor: rule.isActive 
                      ? (isPastDue ? '#ef4444' : isDueToday ? '#f59e0b' : categoryColor) 
                      : '#94a3b8' 
                  }}
                >
                  {getCategoryIcon(rule.category)}
                </div>
                <div className="flex flex-col items-end space-y-2">
                  <div className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                    rule.isActive 
                      ? isPastDue 
                        ? 'bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-400' 
                        : isDueToday
                          ? 'bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-400'
                          : 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' 
                      : 'bg-slate-100 dark:bg-slate-800 text-slate-500'
                  }`}>
                    {rule.frequency}
                  </div>
                  <button 
                    onClick={() => onToggle(rule.id)}
                    className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded transition-colors ${
                      rule.isActive 
                        ? isPastDue ? 'text-red-600 hover:text-red-700' : isDueToday ? 'text-amber-600 hover:text-amber-700' : 'text-emerald-600 hover:text-emerald-700' 
                        : 'text-slate-400 hover:text-indigo-500'
                    }`}
                  >
                    {rule.isActive ? (isPastDue ? 'Overdue' : isDueToday ? 'Due Today' : 'Active') : 'Paused'}
                  </button>
                </div>
              </div>

              <h4 className="font-bold text-slate-800 dark:text-slate-200 text-lg mb-1 truncate">{rule.description}</h4>
              {rule.bankName && (
                <p className="text-xs font-bold text-indigo-500 dark:text-indigo-400 mb-2 truncate">{rule.bankName}</p>
              )}
              <p className="text-2xl font-black text-slate-900 dark:text-white mb-4">{formatCurrency(rule.amount)}</p>

              <div className="space-y-2 border-t border-slate-50 dark:border-slate-800 pt-4">
                <div className="flex justify-between text-xs">
                  <span className="text-slate-400 dark:text-slate-500">Next Due:</span>
                  <div className="text-right">
                    <span className={`font-semibold ${
                      isPastDue ? 'text-red-600 dark:text-red-400' : isDueToday ? 'text-amber-600 dark:text-amber-400' : rule.isActive ? 'text-slate-700 dark:text-slate-300' : 'text-slate-400'
                    }`}>
                      {rule.isActive 
                        ? nextDueDate.toLocaleDateString('en-IN', { month: 'short', day: 'numeric', year: 'numeric' })
                        : 'Paused'}
                    </span>
                    {isPastDue && <div className="text-[10px] font-bold text-red-500 uppercase mt-0.5">Missed Payment</div>}
                    {!isPastDue && isDueToday && <div className="text-[10px] font-bold text-amber-500 uppercase mt-0.5">Payment due now</div>}
                  </div>
                </div>
                <div className="flex justify-between items-center text-xs">
                  <div className="flex items-center overflow-hidden mr-2">
                    <span className="text-slate-400 dark:text-slate-500 shrink-0">Category:</span>
                    <span className="font-semibold text-slate-700 dark:text-slate-300 truncate ml-2">{rule.category}</span>
                  </div>
                  <div className="flex items-center space-x-1 shrink-0">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onEdit(rule);
                      }}
                      className="p-1.5 bg-slate-50 dark:bg-slate-800/50 rounded-lg text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all"
                      title="Edit Rule"
                    >
                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                    </button>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        setDeleteConfirmId(rule.id);
                      }}
                      className="p-1.5 bg-slate-50 dark:bg-slate-800/50 rounded-lg text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all"
                      title="Delete Rule"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Delete Confirmation Dialog */}
      {deleteConfirmId && ruleToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[150] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-white dark:bg-slate-900 rounded-[32px] shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-slate-800">
            <div className="p-8 text-center">
              <div className="w-20 h-20 bg-red-50 dark:bg-red-900/30 rounded-3xl flex items-center justify-center mx-auto mb-6 text-red-600 dark:text-red-400">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </div>
              <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-2 tracking-tight">Delete Recurring Payment?</h3>
              <p className="text-slate-500 dark:text-slate-400 text-sm mb-2">
                This will permanently stop automated tracking for:
              </p>
              <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl mb-8">
                <p className="font-bold text-slate-800 dark:text-slate-200">{ruleToDelete.description}</p>
                <p className="text-sm font-black text-red-500 mt-1">{formatCurrency(ruleToDelete.amount)} / {ruleToDelete.frequency}</p>
              </div>
              <div className="flex flex-col space-y-3">
                <button
                  onClick={() => {
                    onDelete(deleteConfirmId);
                    setDeleteConfirmId(null);
                  }}
                  className="w-full px-4 py-4 rounded-2xl bg-red-600 text-white font-black text-sm hover:bg-red-700 transition-all active:scale-[0.98] shadow-lg shadow-red-100 dark:shadow-none"
                >
                  Delete Permanently
                </button>
                <button
                  onClick={() => setDeleteConfirmId(null)}
                  className="w-full px-4 py-3 rounded-2xl text-slate-500 dark:text-slate-400 font-bold text-sm hover:text-slate-700 dark:hover:text-slate-200 transition-colors"
                >
                  Keep It
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default RecurringManager;

import React, { useState, useEffect, useRef } from 'react';
import { Expense, Category, RecurringFrequency, CategoryItem, DefaultCategory } from '../types';
import { getCategoryIcon } from '../constants';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>, recurringInfo?: { frequency: RecurringFrequency }) => void;
  onClose: () => void;
  initialExpense?: Expense;
  initialRecurringFrequency?: RecurringFrequency;
  categories: CategoryItem[];
  onSwitchToAdd?: () => void;
}

const COMMON_BANKS = [
  "HDFC Bank", "SBI", "ICICI Bank", "Axis Bank", "Kotak Mahindra Bank", 
  "IndusInd Bank", "Yes Bank", "Punjab National Bank", "Bank of Baroda", 
  "Union Bank of India", "Canara Bank", "IDFC First Bank", "Bajaj Finserv", 
  "Tata Capital", "Muthoot Finance", "HDB Financial Services", "Home Credit", 
  "MoneyTap", "KreditBee", "Navi", "Paytm Postpaid", "Amazon Pay Later", 
  "Flipkart Pay Later", "Lazypay", "ZestMoney", "Simpl", "mPokket", "Cashe"
];

const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, initialExpense, initialRecurringFrequency, categories, onSwitchToAdd }) => {
  const [description, setDescription] = useState(initialExpense?.description || '');
  const [amount, setAmount] = useState(initialExpense?.amount.toString() || '');
  const [category, setCategory] = useState<Category>(initialExpense?.category || DefaultCategory.OTHER);
  const [bankName, setBankName] = useState(initialExpense?.bankName || '');
  const [date, setDate] = useState(initialExpense?.date || new Date().toISOString().split('T')[0]);
  const [isRecurring, setIsRecurring] = useState(false);
  const [frequency, setFrequency] = useState<RecurringFrequency>(RecurringFrequency.MONTHLY);
  const [showBankSuggestions, setShowBankSuggestions] = useState(false);
  const [receiptImage, setReceiptImage] = useState<string | null>(initialExpense?.receiptImage || null);
  const [isProcessingImage, setIsProcessingImage] = useState(false);
  const [userHasManuallySetCategory, setUserHasManuallySetCategory] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const isEditMode = !!initialExpense;
  const showBankField = category === DefaultCategory.LOAN || category === DefaultCategory.EMI;

  // Sync state when initialExpense changes (e.g., when switching from Edit to Add mode)
  useEffect(() => {
    if (initialExpense) {
      setDescription(initialExpense.description);
      setAmount(initialExpense.amount.toString());
      setCategory(initialExpense.category);
      setBankName(initialExpense.bankName || '');
      setDate(initialExpense.date);
      setReceiptImage(initialExpense.receiptImage || null);

      if (initialRecurringFrequency) {
        setIsRecurring(true);
        setFrequency(initialRecurringFrequency);
      } else {
        setIsRecurring(false);
      }
      setUserHasManuallySetCategory(false);
    } else {
      // Reset form to default "Add New" state
      setDescription('');
      setAmount('');
      setCategory(DefaultCategory.OTHER);
      setBankName('');
      setDate(new Date().toISOString().split('T')[0]);
      setReceiptImage(null);
      setIsRecurring(false);
      setFrequency(RecurringFrequency.MONTHLY);
      setShowBankSuggestions(false);
      setUserHasManuallySetCategory(false);
    }
  }, [initialExpense, initialRecurringFrequency]);

  const handleImageCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsProcessingImage(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setReceiptImage(reader.result as string);
        setIsProcessingImage(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeReceipt = () => {
    setReceiptImage(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;
    if (showBankField && !bankName) return;

    onAdd(
      {
        description,
        amount: parseFloat(amount),
        category,
        date,
        bankName: showBankField ? bankName : undefined,
        receiptImage: receiptImage || undefined
      },
      isRecurring ? { frequency } : undefined
    );
  };

  const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setCategory(e.target.value as Category);
    setUserHasManuallySetCategory(true);
  };

  const handleClearCategory = () => {
    setCategory(DefaultCategory.OTHER);
    setUserHasManuallySetCategory(true);
  };

  const filteredBanks = bankName 
    ? COMMON_BANKS.filter(b => b.toLowerCase().includes(bankName.toLowerCase()))
    : COMMON_BANKS;

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-t-3xl md:rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in slide-in-from-bottom-full md:slide-in-from-bottom-4 duration-300 border-x border-t md:border border-slate-200 dark:border-slate-800 max-h-[90vh] flex flex-col">

        {/* Drag handle for mobile visual cue */}
        <div className="md:hidden flex justify-center py-3">
          <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full" />
        </div>

        <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-start bg-slate-50/50 dark:bg-slate-800/50 shrink-0">
          <div className="flex flex-col">
            <h2 className="text-xl font-bold text-slate-800 dark:text-white">
              {isEditMode ? 'Edit Expense' : 'Add Expense'}
            </h2>
            {isEditMode && onSwitchToAdd && (
              <button 
                type="button"
                onClick={onSwitchToAdd}
                className="text-xs text-indigo-600 dark:text-indigo-400 font-bold hover:underline text-left mt-1 flex items-center group"
              >
                <svg className="w-3 h-3 mr-1 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" /></svg>
                Switch to Add New
              </button>
            )}
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors text-slate-500">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 overflow-y-auto pb-10 md:pb-6">
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">Description</label>
              <input
                type="text"
                required
                placeholder="Rent, Coffee, Netflix..."
                className="w-full px-4 py-4 md:py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all placeholder:text-slate-400 text-base"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>

            {showBankField && (
              <div className="animate-in slide-in-from-top-2 duration-300 relative z-20">
                <label className="block text-xs font-bold text-indigo-500 dark:text-indigo-400 uppercase tracking-wider mb-2">
                  Bank / Lender Name <span className="text-red-500">*</span>
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-indigo-600 dark:text-indigo-400">
                    <div className="scale-90">
                      {getCategoryIcon(category)}
                    </div>
                  </div>
                  <input
                    type="text"
                    required
                    placeholder="e.g. HDFC Bank, SBI, MoneyTap"
                    className="w-full pl-12 pr-4 py-4 md:py-3 rounded-xl border border-indigo-200 dark:border-indigo-900 bg-indigo-50/30 dark:bg-indigo-900/10 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-400 text-base font-medium"
                    value={bankName}
                    onChange={(e) => {
                      setBankName(e.target.value);
                      setShowBankSuggestions(true);
                    }}
                    onFocus={() => setShowBankSuggestions(true)}
                    onBlur={() => setTimeout(() => setShowBankSuggestions(false), 200)}
                    autoComplete="off"
                  />
                  {showBankSuggestions && filteredBanks.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl max-h-48 overflow-y-auto z-30">
                      {filteredBanks.map((bank) => (
                        <button
                          key={bank}
                          type="button"
                          className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-700 text-sm text-slate-700 dark:text-slate-200 border-b border-slate-50 dark:border-slate-700/50 last:border-0 transition-colors"
                          onClick={() => {
                            setBankName(bank);
